test("all generated target-data JSONL templates are rejected unchanged without side effects", async () => {
  const templateContext = createApiContext({ sessionSecret: "unit-test-secret", auditStore: createMemoryAuditStore() });
  const adminToken = signSessionToken(demoUsers.find((item) => item.id === "demo-admin"), "unit-test-secret");
  const adminHeaders = { authorization: `Bearer ${adminToken}` };

  const targetDataTemplate = await invokeApi(templateContext, {
    method: "GET",
    url: "/api/v1/target-gaps/import-jsonl-template",
    headers: adminHeaders,
  });
  assert.equal(targetDataTemplate.status, 200);
  assert.ok(targetDataTemplate.body.items.length >= 6);
  assert.equal(targetDataTemplate.body.packageImportRoute, "/api/v1/target-gaps/import-jsonl-package");
  assert.ok(targetDataTemplate.body.items.every((item) => item.executionStatus && item.executionStatusReason));
  assert.ok(targetDataTemplate.body.counts.byExecutionStatus.ready_to_collect_data > 0);

  const failures = [];
  for (const item of targetDataTemplate.body.items) {
    assert.equal(item.record.templateOnly, true);
    assert.ok(item.importRoute);
    for (const [kind, route, expectedError] of [
      [
        "per-route",
        item.importRoute,
        item.importRoute === "/api/v1/ratings/import-jsonl" ? "rating_template_record" : "target_data_collection_template_record",
      ],
      ["package", targetDataTemplate.body.packageImportRoute, "target_data_collection_package_template_record"],
    ]) {
      const auditStore = createMemoryAuditStore();
      const context = createApiContext({ sessionSecret: "unit-test-secret", auditStore });
      const unchangedTemplateImport = await invokeApi(context, {
        method: "POST",
        url: route,
        headers: adminHeaders,
        body: JSON.stringify({ jsonl: JSON.stringify(item.record) }),
      });
      const sideEffectCounts = await auditStoreEventCounts(auditStore);
      if (
        unchangedTemplateImport.status < 400 ||
        unchangedTemplateImport.body?.error !== expectedError ||
        totalAuditStoreEventCount(sideEffectCounts) > 0
      ) {
        failures.push({
          kind,
          id: item.id,
          route,
          status: unchangedTemplateImport.status,
          error: unchangedTemplateImport.body?.error ?? null,
          sideEffectCounts,
        });
      }
    }
  }

  assert.deepEqual(failures, []);
});

