  const raterHeaders = { authorization: `Bearer ${raterToken}`, "content-type": "application/json" };
  const operationalControls = completeOperationalControlWorkflowFixtures();
  const assignmentPolicy = operationalControls.queueFreshnessPolicies.find((item) => item.lane === "assignment");
  const assignmentScan = operationalControls.queueStaleByDelayScans.find((item) => item.lane === "assignment");

  const policy = await invokeApi(context, {
    method: "POST",
    url: "/api/v1/queue-freshness-policies",
    headers: adminHeaders,
    body: JSON.stringify({ queueFreshnessPolicy: assignmentPolicy }),
  });
