  const scan = await invokeApi(context, {
    method: "POST",
    url: "/api/v1/queues/assignment/stale-by-delay-scan",
    headers: adminHeaders,
    body: JSON.stringify({ queueStaleByDelayScan: assignmentScan }),
  });
