test("workflow collection readback normalizes row-based admin queues", () => {
  const appSource = readFileSync("src/app.mjs", "utf8");
  const extractFunction = (source, functionName) => {
    const start = source.indexOf(`function ${functionName}`);
    assert.notEqual(start, -1, functionName);
    let depth = 0;
    let opened = false;
    for (let index = start; index < source.length; index += 1) {
      const character = source[index];
      if (character === "{") {
        depth += 1;
        opened = true;
      } else if (character === "}") {
        depth -= 1;
        if (opened && depth === 0) return source.slice(start, index + 1);
      }
    }
    assert.fail(`Could not extract ${functionName}`);
  };
  const helperSource = [
    "const releaseId = 'october-2026-demo';",
    "function releaseReportReadbackItems() { return []; }",
    extractFunction(appSource, "workflowCollectionReadbackBody"),
  ].join("\n");
  const { workflowCollectionReadbackBody } = Function(`${helperSource}; return { workflowCollectionReadbackBody };`)();
  const body = workflowCollectionReadbackBody(
    { id: "prepared-drafts", resourceKey: "preparedDraft" },
    { tabs: ["All drafts"], rows: [{ id: "source-prepared-position", gateReadinessStatus: "ready_for_candidate_item_creation" }] },
  );
  assert.equal(body.resourceKey, "preparedDraft");
  assert.equal(body.count, 1);
  assert.deepEqual(body.items, [{ id: "source-prepared-position", gateReadinessStatus: "ready_for_candidate_item_creation" }]);
  assert.deepEqual(body.tabs, ["All drafts"]);
});

