  assert.equal(queue.body.releaseUseStatus, "operator_evidence_submission_plan_open");
  assert.equal(queue.body.counts.actionItems, queue.body.items.length);
  assert.equal(queue.body.counts.collectDataActionItems, 11);
  assert.equal(queue.body.counts.submitArtifactActionItems, 30);
  assert.equal(queue.body.counts.reviewReportSectionActionItems, 4);
  assert.equal(queue.body.count, queue.body.items.length);
  assert.equal(queue.body.totalCount, queue.body.items.length);
  assert.equal(queue.body.filteredCounts.actionItems, queue.body.items.length);
  assert.equal(queue.body.filteredCounts.openActionItems, queue.body.items.length);
  assert.equal(queue.body.filteredCounts.byStatus.not_submitted, queue.body.items.filter((item) => item.status === "not_submitted").length);
  assert.equal(queue.body.filteredCounts.byBlockedTargetGapId.validation_critiques, 6);
  assert.equal(
    queue.body.filteredCounts.byTemplateCoverageStatus.template_coverage_available,
    queue.body.items.filter((item) => item.templateCoverageStatus === "template_coverage_available").length,
  );
  assert.equal(queue.body.counts.templateCoverageMissingActionItems, 0);
  assert.ok(queue.body.counts.templateCoverageAvailableActionItems > 0);
  assert.equal(
    queue.body.filteredCounts.byPreflightCoverageStatus.preflight_coverage_available,
    queue.body.items.filter((item) => item.preflightCoverageStatus === "preflight_coverage_available").length,
  );
  assert.equal(queue.body.counts.preflightCoverageMissingActionItems, 0);
  assert.ok(queue.body.counts.preflightCoverageAvailableActionItems > 0);
  assert.ok(queue.body.filteredCounts.byPreflightCoverageKind.single_record_dry_run > 0);
  assert.ok(queue.body.filteredCounts.byPreflightCoverageKind.single_record_validate_only > 0);
  assert.equal(
    queue.body.filteredCounts.byGovernanceCoverageStatus.governance_coverage_available,
    queue.body.items.filter((item) => item.governanceCoverageStatus === "governance_coverage_available").length,
  );
  assert.equal(queue.body.counts.governanceCoverageMissingActionItems, 0);
  assert.ok(queue.body.counts.governanceCoverageAvailableActionItems > 0);
  assert.equal(queue.body.filteredCounts.byPolicyActionKind.label_snapshot_freeze, 1);
  assert.equal(queue.body.filteredCounts.bySetupPolicyActionKind.evaluation_run, 3);
  assert.equal(queue.body.filteredCounts.byGovernanceCoverageKind.server_materialized_snapshot, 2);
  assert.equal(
    queue.body.filteredCounts.byRelatedSubmitActionId["model_evaluation_reproducibility:submit:leaderboard_model_run_provenance"],
    1,
  );
  assert.equal(queue.body.filteredCounts.byRelatedArtifactKind.benchmark_freeze_report, 3);
  assert.equal(
    queue.body.filteredCounts.byActionStatus.submit_operator_evidence,
    queue.body.items.filter((item) => item.actionStatus === "submit_operator_evidence").length,
  );
  assert.equal(new Set(queue.body.items.map((item) => item.id)).size, queue.body.items.length);
  assert.ok(queue.body.items.every((item) => item.sourceEvidenceId));
  assert.ok(queue.body.items.every((item) => item.executionStatus && item.executionStatusReason));
  assert.ok(queue.body.items.every((item) => item.templateCoverageStatus));
  assert.ok(queue.body.items.every((item) => Array.isArray(item.templateCoverageRoutes)));
  assert.ok(queue.body.items.every((item) => Array.isArray(item.templateCoverageKinds)));
  assert.ok(queue.body.items.every((item) => item.preflightCoverageStatus));
  assert.ok(queue.body.items.every((item) => Array.isArray(item.preflightCoverageRoutes)));
  assert.ok(queue.body.items.every((item) => Array.isArray(item.preflightCoverageKinds)));
  assert.ok(queue.body.items.every((item) => item.governanceCoverageStatus));
  assert.ok(queue.body.items.every((item) => Array.isArray(item.governanceCoverageRoutes)));
  assert.ok(queue.body.items.every((item) => Array.isArray(item.governanceCoverageKinds)));
  assert.ok(queue.body.items.every((item) => item.governanceCoveragePolicy));
  assert.ok(
    queue.body.items.every(
      (item) =>
        item.operatorActionItemRoute === `/api/v1/operator-action-items/${encodeURIComponent(item.id)}` &&
        item.actionReadbackItemRoute === item.operatorActionItemRoute &&
        Array.isArray(item.routes) &&
        item.routeCount === item.routes.length &&
        item.routes.includes(item.operatorActionItemRoute),
    ),
  );
  assert.deepEqual(
    queue.body.items
      .filter((item) => item.actionType === "submit_artifact" && item.executionStatus !== "closed")
      .filter((item) => item.templateCoverageStatus !== "template_coverage_available" || item.templateCoverageRoutes.length === 0)
      .map((item) => item.id),
    [],
  );
  assert.deepEqual(
    queue.body.items
      .filter((item) => ["collect_data", "submit_artifact"].includes(item.actionType) && item.executionStatus !== "closed")
      .filter((item) => item.preflightCoverageStatus !== "preflight_coverage_available" || item.preflightCoverageRoutes.length === 0)
      .map((item) => item.id),
    [],
  );
