test("production schema includes normalized source-preparation projection tables with service projection RLS", () => {
  const schema = readFileSync("db/production-schema.sql", "utf8");
  const architectureDoc = readFileSync("docs/production-architecture.md", "utf8");
  for (const table of ["prepared_drafts", "review_signals", "gate_decisions", "candidate_items", "promotion_records"]) {
    assert.ok(schema.includes(`create table if not exists ${table}`), table);
    assert.ok(schema.includes(`alter table ${table} enable row level security`), table);
    assert.ok(schema.includes(`create policy ${table}_read_auditors on ${table}`), table);
    assert.ok(schema.includes(`create policy ${table}_write_admin_or_service on ${table}`), table);
  }
  assert.ok(schema.includes("source_argument_extraction_id text references argument_extractions(id)"));
  assert.ok(schema.includes("source_prepared_draft_id text not null references prepared_drafts(id)"));
  assert.ok(schema.includes("target_candidate_item_id text not null references candidate_items(id)"));
  assert.ok(schema.includes("downstream_promotion_status text not null check (downstream_promotion_status = 'not_promoted_to_live')"));
  assert.ok(schema.includes("created_live_record boolean not null default false check (created_live_record = false)"));
  assert.ok(schema.includes("created_candidate_batch boolean not null default false check (created_candidate_batch = false)"));
  assert.ok(schema.includes("create index if not exists prepared_drafts_source_extraction_idx"));
  assert.ok(schema.includes("create index if not exists review_signals_affected_object_idx"));
  assert.ok(schema.includes("create index if not exists gate_decisions_object_idx"));
  assert.ok(schema.includes("create index if not exists promotion_records_target_candidate_item_idx"));
  assert.ok(architectureDoc.includes("source-preparation projection tables"));
  assert.ok(architectureDoc.includes("prepared_drafts"));
  assert.ok(architectureDoc.includes("promotion_records"));
});

