test("postgres audit store projects validated rating audit events into immutable normalized rows", () => {
  const blindRating = {
    ...validBlindRating("rating-projection-blind"),
    rationaleEvidenceSpanIds: ["span-projection-1"],
    lockedBeforePeerExposure: true,
    sourceTagVisibilityState: "hidden_from_initial_rater",
    policyActionKind: "rating_lock",
    policyDecisionId: "policy-decision-rating-projection",
    policyDecisionConsumptionId: "policy-consumption-rating-projection",
    policyDecisionIdempotencyKey: "rating_lock:blind_initial_submitted:rating-projection-blind:root",
  };
  const ratingEvent = {
    id: "event-rating-projection-blind",
    type: "blind_initial_submitted",
    receivedAt: "2026-10-01T00:40:00.000Z",
    actorRole: "rater",
    actorHash: "sha256:rating-projection-actor",
    payloadHash: "sha256:rating-projection-blind",
    payload: { rating: blindRating },
  };
  const projection = ratingProjectionForAuditEvent(ratingEvent);
  assert.equal(projection.table, "ratings");
  assert.equal(projection.values.id, "rating-projection-blind");
  assert.equal(projection.values.kind, "blind_initial");
  assert.equal(projection.values.parent_rating_id, null);
  assert.equal(projection.values.score_input_policy_id, "score-input-policy-workflow-new");
  assert.equal(projection.values.score_explanation_policy_id, "score-explanation-policy-october-2026-demo");
  assert.equal(projection.values.score_confidence_judgment, "medium");
  assert.equal(projection.values.policy_decision_id, "policy-decision-rating-projection");
  assert.deepEqual(projection.values.rationale_evidence_span_ids, ["span-projection-1"]);
  assert.equal(projection.values.locked_before_peer_exposure, true);
  assert.equal(projection.values.source_tag_visibility_state, "hidden_from_initial_rater");
  assert.deepEqual(
    projection.values.score_rows.map((row) => [row.dimension, row.score_value, row.raw_score_value, row.displayed_score_value]),
    [
      ["centrality", 0.7, 0.7, 0.7],
      ["strength", 0.68, 0.68, 0.68],
      ["correctness", 0.9, 0.9, 0.9],
      ["clarity", 0.88, 0.88, 0.88],
      ["dead_weight", 0.05, 0.05, 0.05],
      ["single_issue", 0.92, 0.92, 0.92],
      ["overall", 0.62, 0.62, 0.62],
    ],
  );

  const revision = {
    ...validBlindRating("rating-projection-revision"),
    kind: "revision",
    parentRatingId: "rating-projection-blind",
    revisionReasonCode: "human_only_self_check",
    submittedAt: "2026-10-02T00:40:00.000Z",
    lockedAt: "2026-10-02T00:40:00.000Z",
  };
  const revisionProjection = ratingProjectionForAuditEvent({
    ...ratingEvent,
    id: "event-rating-projection-revision",
    type: "revision_submitted",
    payloadHash: "sha256:rating-projection-revision",
    payload: { rating: revision },
  });
  assert.equal(revisionProjection.values.kind, "revision");
  assert.equal(revisionProjection.values.parent_rating_id, "rating-projection-blind");
  assert.equal(revisionProjection.values.score_rows.length, 7);

  const lowClarityRating = withScoreExplanationEvidence({
    ...validBlindRating("rating-projection-low-clarity"),
    scores: {
      centrality: null,
      strength: null,
      correctness: 0.5,
      clarity: 0.32,
      dead_weight: null,
      single_issue: null,
      overall: 0.12,
    },
    rawScores: {
      centrality: null,
      strength: null,
      correctness: 0.5,
      clarity: 0.32,
      dead_weight: null,
      single_issue: null,
      overall: 0.12,
    },
    displayedScores: {
      centrality: null,
      strength: null,
      correctness: 0.5,
      clarity: 0.32,
      dead_weight: null,
      single_issue: null,
      overall: 0.12,
    },
    scoreEntryExplicitnessStatus: "low_clarity_branch_explicit",
    scoreMissingFieldValidationStatus: "low_clarity_provisional_fields_allowed",
    provisionalDimensions: ["centrality", "strength", "dead_weight", "single_issue"],
  });
  const lowClarityProjection = ratingProjectionForAuditEvent({
    ...ratingEvent,
    id: "event-rating-projection-low-clarity",
    payload: { rating: lowClarityRating },
  });
  assert.deepEqual(
    lowClarityProjection.values.score_rows
      .filter((row) => row.low_clarity_provisional)
      .map((row) => row.dimension),
    ["centrality", "strength", "dead_weight", "single_issue"],
  );
  assert.equal(lowClarityProjection.values.score_rows.find((row) => row.dimension === "centrality").score_value, null);

  assert.equal(ratingProjectionForAuditEvent({ id: "event-no-rating", payload: {} }), null);
});

test("production schema includes append-only workflow state transition projection table", () => {
  const schema = readFileSync("db/production-schema.sql", "utf8");
  const architectureDoc = readFileSync("docs/production-architecture.md", "utf8");
  assert.ok(schema.includes("create table if not exists workflow_state_transition_logs"));
  assert.ok(schema.includes("alter table workflow_state_transition_logs enable row level security"));
  assert.ok(schema.includes("create policy workflow_state_transition_logs_read_auditors on workflow_state_transition_logs"));
  assert.ok(schema.includes("create policy workflow_state_transition_logs_write_admin_or_service on workflow_state_transition_logs"));
  assert.ok(schema.includes("entity_type text not null check"));
  assert.ok(schema.includes("'assignment'"));
  assert.ok(schema.includes("'release_version'"));
  assert.ok(schema.includes("transition_status text not null check (transition_status in ('accepted_guarded_transition', 'rejected_guarded_transition'))"));
  assert.ok(schema.includes("guard_checks jsonb not null default '[]'::jsonb"));
  assert.ok(schema.includes("failed_guard_reasons jsonb not null default '[]'::jsonb"));
  assert.ok(schema.includes("source_tag_protected_visibility_state text not null"));
  assert.ok(schema.includes("create index if not exists workflow_state_transition_logs_entity_idx"));
  assert.ok(architectureDoc.includes("workflow-state transition logs"));
  assert.ok(architectureDoc.includes("accepted and rejected backend-guarded transitions"));
  assert.ok(architectureDoc.includes("Workflow transition rows are insert-only by transition id"));
});

test("postgres audit store projects workflow state transition events into normalized rows", () => {
  const acceptedTransition = {
    id: "workflow-transition-projection-accepted",
    entityType: "rating",
    entityId: "rating-projection-blind",
    assignmentId: "assign-ai-base-rate",
    priorState: "draft",
    requestedNextState: "locked_initial",
    acceptedNextState: "locked_initial",
    actorId: "demo-rater",
    actorRole: "rater",
    guardChecks: ["initial_rating_payload_valid", "source_tag_protected_visibility_preserved"],
    failedGuardReasons: [],
    lockFreezeArtifactIds: ["rating-projection-blind"],
    sourceTagProtectedVisibilityState: "source_tag_protected_visibility_preserved",
    timestamp: "2026-10-01T00:45:00.000Z",
  };
  const acceptedProjection = workflowStateTransitionProjectionForWorkflowEvent({
    id: "event-workflow-transition-projection-accepted",
    type: "workflow_state_transition_accepted",
    receivedAt: "2026-10-01T00:45:01.000Z",
    actorHash: "sha256:workflow-transition-actor",
    payloadHash: "sha256:workflow-transition-projection-accepted",
    resourceKey: "workflowStateTransitionLog",
    resourceId: acceptedTransition.id,
    payload: { workflowStateTransitionLog: acceptedTransition },
  });
  assert.equal(acceptedProjection.table, "workflow_state_transition_logs");
  assert.equal(acceptedProjection.values.transition_status, "accepted_guarded_transition");
  assert.equal(acceptedProjection.values.entity_type, "rating");
  assert.equal(acceptedProjection.values.prior_state, "draft");
  assert.equal(acceptedProjection.values.accepted_next_state, "locked_initial");
  assert.deepEqual(acceptedProjection.values.guard_checks, [
    "initial_rating_payload_valid",
    "source_tag_protected_visibility_preserved",
  ]);
  assert.deepEqual(acceptedProjection.values.failed_guard_reasons, []);
  assert.deepEqual(acceptedProjection.values.lock_freeze_artifact_ids, ["rating-projection-blind"]);

  const rejectedTransition = {
    ...acceptedTransition,
    id: "workflow-transition-projection-rejected",
    priorState: "locked_initial",
    requestedNextState: "draft",
    acceptedNextState: "locked_initial",
    guardChecks: ["preserve_original_locked_rating"],
    failedGuardReasons: ["transition_not_allowed:locked_initial->draft"],
    timestamp: "2026-10-01T00:46:00.000Z",
  };
  const rejectedProjection = workflowStateTransitionProjectionForWorkflowEvent({
    id: "event-workflow-transition-projection-rejected",
    type: "workflow_state_transition_rejected",
    receivedAt: "2026-10-01T00:46:01.000Z",
    actorHash: "sha256:workflow-transition-actor",
    payloadHash: "sha256:workflow-transition-projection-rejected",
    resourceKey: "workflowStateTransitionLog",
    resourceId: rejectedTransition.id,
    payload: { workflowStateTransitionLog: rejectedTransition },
  });
  assert.equal(rejectedProjection.values.transition_status, "rejected_guarded_transition");
  assert.equal(rejectedProjection.values.accepted_next_state, "locked_initial");
  assert.deepEqual(rejectedProjection.values.failed_guard_reasons, ["transition_not_allowed:locked_initial->draft"]);

  assert.equal(
    workflowStateTransitionProjectionForWorkflowEvent({
      id: "event-not-transition",
      resourceKey: "policyDecisionRecord",
      payload: { policyDecisionRecord: { id: "policy-decision-not-transition" } },
    }),
    null,
  );
});

test("production schema includes normalized RLHF90 operational-control projection tables", () => {
  const schema = readFileSync("db/production-schema.sql", "utf8");
  const architectureDoc = readFileSync("docs/production-architecture.md", "utf8");
  for (const table of [
    "policy_action_kinds",
    "policy_decisions",
    "policy_decision_consumptions",
    "implementation_phase_gate_bundles",
    "implementation_phase_gate_lanes",
  ]) {
    assert.ok(schema.includes(`create table if not exists ${table}`), table);
    assert.ok(schema.includes(`alter table ${table} enable row level security`), table);
    assert.ok(schema.includes(`create policy ${table}_read_auditors on ${table}`), table);
    assert.ok(schema.includes(`create policy ${table}_write_admin_or_service on ${table}`), table);
  }
  assert.ok(schema.includes("requires_current_decision boolean not null check (requires_current_decision = true)"));
  assert.ok(schema.includes("wrong_scope_behavior text not null check (wrong_scope_behavior = 'fail_closed')"));
  assert.ok(schema.includes("manifest_hash text not null check (manifest_hash like 'sha256:%')"));
  assert.ok(schema.includes("phase_gate_bundle_hash text not null check (phase_gate_bundle_hash like 'sha256:%')"));
  assert.ok(schema.includes("future_phase_default text not null check (future_phase_default = 'blocked')"));
  assert.ok(schema.includes("fail_closed boolean not null check (fail_closed = true)"));
  assert.ok(schema.includes("no_side_effects_when_disabled boolean not null check (no_side_effects_when_disabled = true)"));
  assert.ok(schema.includes("labels_exposed_when_disabled boolean not null check (labels_exposed_when_disabled = false)"));
  assert.ok(schema.includes("supports_release_claims_when_disabled boolean not null check (supports_release_claims_when_disabled = false)"));
  assert.ok(schema.includes("create index if not exists policy_decisions_action_kind_idx"));
  assert.ok(schema.includes("create index if not exists implementation_phase_gate_lanes_state_idx"));
  assert.ok(architectureDoc.includes("operational-control tables"));
  assert.ok(architectureDoc.includes("policy_action_kinds"));
  assert.ok(architectureDoc.includes("implementation_phase_gate_lanes"));
  assert.ok(architectureDoc.includes("Phase 1 source-intake"));
  assert.ok(architectureDoc.includes("operational-control events"));
});

test("postgres audit store projects RLHF90 operational-control workflow events into normalized rows", () => {
  const baseEvent = (resourceKey, resource) => ({
    id: `event-${resource.id}`,
    type: `${resourceKey}_submitted`,
    resourceKey,
    resourceId: resource.id,
    payloadHash: `sha256:${resource.id}`,
    payload: { [resourceKey]: resource },
  });

  const policyActionKind = {
    id: "policy-action-kind-projection-rating-lock",
    actionKind: "rating_lock",
    requiresCurrentDecision: true,
    requiresManifestBinding: true,
    requiresActorBinding: true,
    requiresOutputSchemaBinding: true,
    requiresPhaseGateBinding: true,
    requiresIdempotencyBinding: true,
    replayProtection: "idempotency_bound",
    wrongScopeBehavior: "fail_closed",
    activatedAt: "2026-10-01T00:10:00.000Z",
  };
  const policyActionKindProjection = operationalControlProjectionForWorkflowEvent(
    baseEvent("policyActionKind", policyActionKind),
  );
  assert.equal(policyActionKindProjection.table, "policy_action_kinds");
  assert.equal(policyActionKindProjection.values.action_kind, "rating_lock");
  assert.equal(policyActionKindProjection.values.requires_manifest_binding, true);
  assert.equal(policyActionKindProjection.values.wrong_scope_behavior, "fail_closed");

  const policyDecision = {
    id: "policy-decision-projection-rating-lock",
    actionKindId: policyActionKind.id,
    actionKind: "rating_lock",
    decisionStatus: "allow",
    actorId: "demo-admin",
    actorRole: "admin",
    manifestId: "release-config-manifest-projection",
    manifestHash: "sha256:release-config-manifest-projection",
    phaseGateBundleId: "implementation-phase-gate-projection",
    phaseGateBundleHash: "sha256:implementation-phase-gate-projection",
    releaseId: "october-2026-demo",
    outputSchemaVersion: "lmca-rating-lock-workflow-v1",
    outputSchemaHash: "sha256:lmca-rating-lock-workflow-v1",
    targetArtifactIds: ["rating-projection"],
    idempotencyKey: "rating_lock:rating_submitted:rating-projection:root",
    singleUse: true,
    replayStatus: "unused",
    manifestBindingStatus: "matched",
    outputSchemaBindingStatus: "matched",
    phaseGateBindingStatus: "matched",
    idempotencyBindingStatus: "matched",
    expiresAt: "2026-10-01T00:15:00.000Z",
    decidedAt: "2026-10-01T00:10:00.000Z",
  };
  const policyDecisionProjection = operationalControlProjectionForWorkflowEvent(
    baseEvent("policyDecisionRecord", policyDecision),
  );
  assert.equal(policyDecisionProjection.table, "policy_decisions");
  assert.equal(policyDecisionProjection.values.manifest_hash, "sha256:release-config-manifest-projection");
  assert.equal(policyDecisionProjection.values.phase_gate_binding_status, "matched");
  assert.deepEqual(policyDecisionProjection.values.target_artifact_ids, ["rating-projection"]);

  const policyDecisionConsumption = {
    id: "policy-decision-consumption-projection-rating-lock",
    decisionId: policyDecision.id,
    actionKind: "rating_lock",
    manifestId: policyDecision.manifestId,
    manifestHash: policyDecision.manifestHash,
    phaseGateBundleId: policyDecision.phaseGateBundleId,
    phaseGateBundleHash: policyDecision.phaseGateBundleHash,
    outputSchemaVersion: policyDecision.outputSchemaVersion,
    outputSchemaHash: policyDecision.outputSchemaHash,
    idempotencyKey: policyDecision.idempotencyKey,
    replayRejected: false,
    scopeMatched: true,
    consumedAt: "2026-10-01T00:10:01.000Z",
  };
  const policyDecisionConsumptionProjection = operationalControlProjectionForWorkflowEvent(
    baseEvent("policyDecisionConsumption", policyDecisionConsumption),
  );
  assert.equal(policyDecisionConsumptionProjection.table, "policy_decision_consumptions");
  assert.equal(policyDecisionConsumptionProjection.values.decision_id, policyDecision.id);
  assert.equal(policyDecisionConsumptionProjection.values.replay_rejected, false);
  assert.equal(policyDecisionConsumptionProjection.values.scope_matched, true);

  const implementationPhaseGateBundle = {
    id: "implementation-phase-gate-projection",
    releaseId: "october-2026-demo",
    manifestId: "release-config-manifest-projection",
    version: "implementation-phase-gate-rlhf90-v1",
    futurePhaseDefault: "blocked",
    broadeningRequiresManifestActivation: true,
    frozenAt: "2026-10-01T00:12:00.000Z",
    laneStates: [
      {
        laneKind: "route",
        phaseState: "enabled",
        allowedActionKinds: ["rating_lock"],
        requiredFeatureFlags: ["ratings_enabled"],
        unavailableResponseClass: "generic_unavailable",
        rolloutOwner: "demo-admin",
        failClosed: true,
        noSideEffectsWhenDisabled: true,
        labelsExposedWhenDisabled: false,
        supportsReleaseClaimsWhenDisabled: false,
      },
      {
        laneKind: "hidden_benchmark_submission_lane",
        phaseState: "blocked",
        allowedActionKinds: [],
        requiredFeatureFlags: [],
        unavailableResponseClass: "generic_denied",
        rolloutOwner: "demo-admin",
        failClosed: true,
        noSideEffectsWhenDisabled: true,
        labelsExposedWhenDisabled: false,
        supportsReleaseClaimsWhenDisabled: false,
      },
    ],
  };
  const implementationPhaseProjection = operationalControlProjectionForWorkflowEvent(
    baseEvent("implementationPhaseGateBundle", implementationPhaseGateBundle),
  );
  assert.equal(implementationPhaseProjection.table, "implementation_phase_gate_bundles");
  assert.equal(implementationPhaseProjection.values.future_phase_default, "blocked");
  assert.equal(implementationPhaseProjection.values.broadening_requires_manifest_activation, true);
  assert.deepEqual(
    implementationPhaseProjection.values.lane_rows.map((row) => [row.lane_kind, row.phase_state, row.position_index]),
    [
      ["route", "enabled", 0],
      ["hidden_benchmark_submission_lane", "blocked", 1],
    ],
  );
  assert.deepEqual(implementationPhaseProjection.values.lane_rows[0].allowed_action_kinds, ["rating_lock"]);
  assert.equal(implementationPhaseProjection.values.lane_rows[1].labels_exposed_when_disabled, false);

  assert.equal(
    operationalControlProjectionForWorkflowEvent(baseEvent("sourceCard", { id: "source-card-not-operational-control" })),
    null,
  );
});

